++                        var_ref->header.ref_count = 1;
++                        var_ref->is_detached = true;
++                        init_list_head(&var_ref->header.link);
++                        JSValue val = (cv->var_idx < num_locals) ? locals[cv->var_idx] : JS_UNDEFINED;
++                        var_ref->value = js_dup(val);
++                        var_ref->pvalue = &var_ref->value;
++                    }
++                }
++                if (!var_ref)
++                    goto fail_v2;
++            } else {
++                /* Parent closure reference */
++                if (cur_var_refs && cur_var_refs[cv->var_idx]) {
++                    var_ref = cur_var_refs[cv->var_idx];
++                    var_ref->header.ref_count++;
++                } else {
++                    var_ref = js_malloc(ctx, sizeof(JSVarRef));
++                    if (!var_ref)
++                        goto fail_v2;
++                    var_ref->header.ref_count = 1;
++                    var_ref->is_detached = true;
++                    init_list_head(&var_ref->header.link);
++                    var_ref->value = JS_UNDEFINED;
++                    var_ref->pvalue = &var_ref->value;
++                }
++            }
++            var_refs[i] = var_ref;
++        }
++    }
++
++    name_atom = b->func_name;
++    if (name_atom == JS_ATOM_NULL)
++        name_atom = JS_ATOM_empty_string;
++    js_function_set_properties(ctx, func_obj, name_atom, b->defined_arg_count);
++
++    if (b->has_prototype) {
++        JS_SetConstructorBit(ctx, func_obj, true);
++        JS_DefineAutoInitProperty(ctx, func_obj, JS_ATOM_prototype,
++                                  JS_AUTOINIT_ID_PROTOTYPE, NULL,
++                                  JS_PROP_WRITABLE);
++    }
++    return func_obj;
++fail_v2:
++    JS_FreeValue(ctx, func_obj);
++    return JS_EXCEPTION;
++}
